mapper.update:
update report_base_${tableName}
set is_delete = 1
where id = #{baseId}

mapper.select:
select  id, ${tableName}_name as baseName, address, ${tableName}_phone phone, contact_people contactPeople,
contact_phone contactPhone, business_license businessLicense, legal_person legalPerson,
 legal_idcard legalIdcard, create_time createTime
from report_base_${tableName}
where is_delete = 0 and ${tableName}_name = #{spotName}
